.card { grid-row-end: span var(--span,18); border-radius: 8px; overflow: hidden; }
@media (max-width: 1024px) { .grid { grid-template-columns: repeat(2, 1fr); } }
@media (max-width: 600px) { .grid { grid-template-columns: 1fr; } .rail { position: fixed; bottom: 0; width: 100%; } }
