```javascript
/* CSS (density vars and grid) */
:root{ --pad:16px; --gap:16px; --font:16px; }
body.compact{ --pad:8px; --gap:12px; --font:14px; }
.gallery{ display:grid; grid-template-columns: repeat(3, 1fr); gap: var(--gap); padding: var(--pad); }
@media (max-width: 900px){ .gallery{ grid-template-columns: repeat(2, 1fr); } }
@media (max-width: 600px){ .gallery{ grid-template-columns: 1fr; } }
.card{ padding: calc(var(--pad) * 0.75); border:1px solid #ddd; border-radius:8px; background:#fff; animation: enter 0.4s var(--delay,0s) ease; }
.thumb{ aspect-ratio:16/9; background:#eee; border-radius:6px; }
@keyframes enter{ from{ transform: translateY(6px); opacity:0; } to{ transform: translateY(0); opacity:1; } }
```

