## Code Example
```javascript
function createUserLoader() {
  const inFlight = new Map(); // id -> Promise
  const cache = new Map(); // id -> { data, expiry }
  const queue = [];
  const MAX_CONCURRENCY = 3;
  let active = 0;

  const fetchUser = async (id) => {
    const res = await fetch(`/api/user/${id}`);
    if (!res.ok) throw new Error('Network error');
    return res.json();
  };

  const tryStart = () => {
    while (active < MAX_CONCURRENCY && queue.length) {
      const { id, resolve, reject } = queue.shift();
      active++;
      const p = fetchUser(id)
        .then((data) => {
          cache.set(id, { data, expiry: Date.now() + 5 * 60 * 1000 });
          inFlight.delete(id);
          resolve(data);
        })
        .catch((err) => reject(err))
        .finally(() => { active--; tryStart(); });
      inFlight.set(id, p);
    }
  };

  const loadUser = (id) => {
    const cached = cache.get(id);
    if (cached && cached.expiry > Date.now()) return Promise.resolve(cached.data);
    if (inFlight.has(id)) return inFlight.get(id);
    return new Promise((resolve, reject) => {
      queue.push({ id, resolve, reject });
      tryStart();
    });
  };

  return { loadUser };
}

// Usage
// const loader = createUserLoader();
// loader.loadUser('123').then(console.log);
```

