// Sketch
function TenantPageLoader() {
  const cache = new Map();
  const inFlight = new Map();
  const ttl = 2 * 60 * 1000;
  const max = 50;

  function key(t,p){return t+':'+p}
  async function fetchPage(t, p){
    const url = `/api/${t}/items?page=${p}`;
    const resp = await fetch(url);
    const data = await resp.json();
    cache.set(key(t,p), { data, expiresAt: Date.now()+ttl });
    inFlight.delete(key(t,p));
    return data;
  }
  return {
    getPage: function(tenantId, page){
      const k = key(tenantId, page);
      const now = Date.now();
      if (cache.has(k)){
        const entry = cache.get(k);
        if (entry.expiresAt>now) return Promise.resolve(entry.data);
        cache.delete(k);
      }
      if (inFlight.has(k)) return inFlight.get(k);
      const p = fetchPage(tenantId, page);
      inFlight.set(k, p);
      p.then(()=>{},()=>{});
      // simple eviction
      if (cache.size>max){
        const first = cache.keys().next().value; cache.delete(first);
      }
      return p;
    },
    clearCache: function(){ cache.clear(); inFlight.clear(); }
  }
}
```

