```javascript
function createPresenceCache(fetchPresence, { ttl = 30000, maxInFlight = 5, onUpdate } = {}) {
  const cache = new Map();
  const inFlight = new Map();
  const waitQueue = [];

  function drain() {
    if (inFlight.size >= maxInFlight || waitQueue.length === 0) return;
    const next = waitQueue.shift();
    if (!next) return;
    const { userId, resolve } = next;
    const p = fetchPresence(userId).then(status => {
      cache.set(userId, { status, expires: Date.now() + ttl });
      if (onUpdate) onUpdate(userId, status);
      inFlight.delete(userId);
      resolve(status);
      drain();
      return status;
    }).catch(err => { inFlight.delete(userId); throw err; });
    inFlight.set(userId, p);
  }

  async function getPresence(userId) {
    const cached = cache.get(userId);
    if (cached && cached.expires > Date.now()) return cached.status;
    return new Promise((resolve, reject) => {
      waitQueue.push({ userId, resolve, reject });
      drain();
    }).then(status => status);
  }

  function clear(userId) {
    cache.delete(userId);
  }

  return { getPresence, clear };
}
```

