## Why This Is Asked
This question tests advanced JavaScript patterns including closures, per-key caching, in-flight deduplication, concurrency control, TTL semantics, and dynamic import boundaries.

## Key Concepts
- **Closures**: Hide internal state from outside access
- **Per-key caching with TTL**: Store module exports with expiration timestamps
- **In-flight deduplication**: Return the same Promise for concurrent requests to the same module
- **Semaphore-like concurrency cap**: Limit simultaneous imports using a counter
- **Background refresh**: Refresh expired modules without blocking subsequent requests

## Code Example
```javascript
function createModuleCache(moduleMap, { ttlMs = 120000, maxInFlight = 3 } = {}) {
  const inFlight = new Map(); // moduleName -> Promise
  const cache = new Map(); // moduleName -> { value, expiry }
  let currentInFlight = 0;

  const acquire = () => new Promise(resolve => {
    const tryAcquire = () => {
      if (currentInFlight < maxInFlight) {
        currentInFlight++;
        resolve();
      } else {
        setTimeout(tryAcquire, 10);
      }
    };
    tryAcquire();
  });

  const release = () => { currentInFlight--; };

  async function load(moduleName) {
    const cached = cache.get(moduleName);
    const isExpired = !cached || Date.now() > cached.expiry;

    if (cached && !isExpired) {
      if (isExpired) {
        load(moduleName).catch(() => {}); // background refresh
      }
      return cached.value;
    }

    if (inFlight.has(moduleName)) {
      return inFlight.get(moduleName);
    }

    const promise = (async () => {
      await acquire();
      try {
        const module = await dynamicImport(moduleMap[moduleName]);
        cache.set(moduleName, {
          value: module,
          expiry: Date.now() + ttlMs
        });
        return module;
      } finally {
        release();
        inFlight.delete(moduleName);
      }
    })();

    inFlight.set(moduleName, promise);
    return promise;
  }

  function invalidate(moduleName) {
    cache.delete(moduleName);
  }

  return { load, invalidate };
}
```

