function createMemoizedAsync(fn, ttl) {
  const cache = new Map();
  return async (id) => {
    const now = Date.now();
    const entry = cache.get(id);
    if (entry && now - entry.t < ttl) return entry.p;
    const p = fn(id);
    cache.set(id, { t: now, p });
    setTimeout(() => {
      const e = cache.get(id);
      if (e && e.p === p) cache.delete(id);
    }, ttl);
    try {
      return await p;
    } catch (e) {
      cache.delete(id);
      throw e;
    }
  };
}
