## Key Concepts
- Closures to encapsulate private state (inFlight, cache, batch)
- Shared Promises for identical keys to prevent duplicate fetches
- Debounced batching with batchDelay and maxBatchSize
- Cache population and correct mapping from response to keys
- Error handling and late responses without memory leaks

## Code Example
```javascript
function createBatcher(fetchFn, { batchDelay = 50, maxBatchSize = 20 } = {}) {
  const cache = new Map();
  const inFlight = new Map();
  let batch = new Set();
  let timer = null;

  function flush() {
    const keys = Array.from(batch).slice(0, maxBatchSize);
    batch.clear();
    timer = null;
    if (keys.length === 0) return;
    const p = fetchFn(keys);
    keys.forEach(k => inFlight.delete(k));
    p.then(res => {
      keys.forEach(k => {
        if (res.hasOwnProperty(k)) {
          cache.set(k, res[k]);
          const { resolve } = inFlight.get(k) || {};
          if (resolve) resolve(res[k]);
          inFlight.delete(k);
        }
      });
    }).catch(err => {
      keys.forEach(k => {
        const { reject } = inFlight.get(k) || {};
        if (reject) reject(err);
        inFlight.delete(k);
      });
    });
  }

  function enqueue(key) {
    if (cache.has(key)) return Promise.resolve(cache.get(key));
    if (inFlight.has(key)) return inFlight.get(key).promise;

    let resolve, reject;
    const promise = new Promise((res, rej) => { resolve = res; reject = rej; });
    inFlight.set(key, { promise, resolve, reject });
    batch.add(key);

    if (!timer) timer = setTimeout(flush, batchDelay);
    return promise;
  }

  return {
    get: (key) => enqueue(key),
    clearCache: () => cache.clear(),
  };
}
```

