Use a closure to hold a cache Map (url -> {data, expiry, promise}). The load(url) method checks if a valid (non-expired) entry exists and returns cached data via Promise.resolve. If a fetch is already in-flight for the same URL, return the existing promise to coalesce concurrent requests. Otherwise, create a new fetch promise, store it in the cache with the expiry timestamp, and return it.

**Example Implementation:**
```javascript
function createDataLoader(fetchFn, ttlMs) {
  const cache = new Map();

  return {
    load(url) {
      if (!url || typeof url !== 'string') {
        return Promise.reject(new Error('Invalid URL'));
      }

      const now = Date.now();
      const cached = cache.get(url);

      if (cached && cached.expiry > now) {
        if (cached.promise) return cached.promise;
        return Promise.resolve(cached.data);
      }

      if (cached && cached.promise) {
        return cached.promise;
      }

      const promise = fetchFn(url)
        .then(data => {
          const entry = cache.get(url);
          if (entry) {
            entry.data = data;
            entry.expiry = now + ttlMs;
            entry.promise = null;
          }
          return data;
        })
        .catch(err => {
          cache.delete(url);
          throw err;
        });

      cache.set(url, { data: null, expiry: now + ttlMs, promise });
      return promise;
    },

    clear(url) {
      if (url) cache.delete(url);
      else cache.clear();
    }
  };
}
```

**Usage:**
```javascript
const loader = createDataLoader(url => fetch(url).then(r => r.json()), 5000);

loader.load('https://api.example.com/data');
loader.load('https://api.example.com/data'); // Returns same promise as above
```

**Edge Cases:**
- Invalid URLs: Reject with error
- Network errors: Clear cache entry and rethrow
- Expired cache: Fetch fresh data

