```javascript
function createPageLoader(fetchFn) {
  const cache = new Map();
  const inflight = new Map();

  function getCacheKey(page, pageSize, sortKey) {
    return `${page}-${pageSize}-${sortKey}`;
  }

  function loadPage(page, pageSize, sortKey) {
    const key = getCacheKey(page, pageSize, sortKey);

    if (cache.has(key)) {
      return Promise.resolve(cache.get(key));
    }

    if (inflight.has(key)) {
      return inflight.get(key);
    }

    const controller = new AbortController();
    const promise = fetchFn(page, pageSize, sortKey, controller.signal)
      .then(data => {
        cache.set(key, data);
        inflight.delete(key);
        return data;
      })
      .catch(err => {
        inflight.delete(key);
        throw err;
      });

    inflight.set(key, promise);
    return promise;
  }

  function invalidate(page, pageSize, sortKey) {
    const key = getCacheKey(page, pageSize, sortKey);
    cache.delete(key);
    inflight.delete(key);
  }

  return { loadPage, invalidate };
}

// Demo
const loader = createPageLoader(async (page, pageSize, sortKey, signal) => {
  const response = await fetch(`/api/items?page=${page}&size=${pageSize}&sort=${sortKey}`, { signal });
  return response.json();
});

// Load two pages
loader.loadPage(1, 10, 'name').then(console.log);
loader.loadPage(2, 10, 'name').then(console.log);

// Invalidate one key
loader.invalidate(1, 10, 'name');

// Simulate cancellation on navigation
const controller = new AbortController();
const pending = loader.loadPage(1, 10, 'name');
controller.abort();
```

