- Simple pub/sub for updates without external libs

## Code Example
```javascript
function createNotificationCache(fetchFn, ttlMs) {
  const store = new Map();
  return {
    get(userId) {
      const entry = store.get(userId) || { data: null, inFlight: null, expiry: 0, listeners: [] };
      if (entry.inFlight) return entry.inFlight;
      const p = fetchFn(userId).then(d => {
        entry.data = d;
        entry.expiry = Date.now() + ttlMs;
        entry.inFlight = null;
        return d;
      }).catch(e => { entry.inFlight = null; throw e; });
      entry.inFlight = p;
      store.set(userId, entry);
      return p;
    },
    refresh(userId) {
      const entry = store.get(userId) || { inFlight: null };
      const p = fetchFn(userId).then(d => {
        entry.data = d; entry.expiry = Date.now() + ttlMs; entry.inFlight = null; return d;
      });
      entry.inFlight = p; store.set(userId, entry); return p;
    },
    onUpdate(userId, cb) {
      const entry = store.get(userId) || { listeners: [] };
      entry.listeners.push(cb);
      store.set(userId, entry);
      return () => {
        entry.listeners = entry.listeners.filter(x => x !== cb);
      };
    }
  };
}
```

