## Why This Is Asked

This question tests practical streaming data handling in the browser: async iteration, backpressure management, error handling, and cancellation. It mirrors real-world applications that consume large event streams, logs, or real-time data feeds.

## Key Concepts

- **Fetch streaming responses** and ReadableStream APIs
- **NDJSON parsing** with line-by-line buffering
- **AsyncIterator** / for await...of syntax
- **Backpressure** with bounded queues (max 5 items)
- **AbortController** for cancellation and proper error propagation
- **Closures** to encapsulate internal state (buffer, reader, etc.)

## Code Example

```javascript
function createStreamingFetcher(url) {
  const controller = new AbortController();
  const buffer = [];
  let resolveNext;
  let rejectNext;

  const queue = new Promise((resolve, reject) => {
    resolveNext = resolve;
    rejectNext = reject;
  });

  async function start() {
    const response = await fetch(url, { signal: controller.signal });
    const reader = response.body.getReader();
    const decoder = new TextDecoder();
    let buffer = '';

    while (true) {
      const { done, value } = await reader.read();
      if (done) {
        if (buffer.trim()) {
          try {
            resolveNext(JSON.parse(buffer));
          } catch (e) {
            rejectNext(new Error('Invalid NDJSON'));
          }
        }
        break;
      }

      buffer += decoder.decode(value, { stream: true });
      const lines = buffer.split('\n');
      buffer = lines.pop();

      for (const line of lines) {
        if (line.trim()) {
          try {
            resolveNext(JSON.parse(line));
          } catch (e) {
            rejectNext(new Error('Invalid NDJSON'));
          }
          if (buffer.length >= 5) {
            await queue;
          }
        }
      }
    }
  }

  start().catch(e => rejectNext(e));

  return {
    stream: {
      [Symbol.asyncIterator]() {
        return {
          next() {
            return queue.then(v => ({ value: v, done: false }));
          }
        };
      }
    },
    cancel: () => controller.abort()
  };
}
```

## Follow-up Questions

- How would you handle different NDJSON formats or malformed lines?
- How does backpressure work when the consumer is slower than the stream?
- How would you add retry logic on network failures?

## Why This Is Asked

This question tests understanding of dynamic imports, caching strategies, concurrency handling, and import maps in the browser. It evaluates the ability to handle circular dependencies and cross-origin concerns while maintaining strict singleton semantics.

## Key Concepts

- Dynamic import() and module namespace objects
- Per-origin caching with inFlight deduplication
- Circular dependency handling without deadlocks
- Import maps specifier remapping
- Preload strategy and race condition management

## Code Example

```javascript
// Per-origin cache keyed by origin + URL
const moduleCache = new Map();
const inFlight = new Map();

async function loadModule(url, importMap) {
  const cacheKey = new URL(url).origin + new URL(url).pathname;

  if (moduleCache.has(cacheKey)) {
    return moduleCache.get(cacheKey);
  }

  if (inFlight.has(cacheKey)) {
    return inFlight.get(cacheKey);
  }

  const loadPromise = performLoad(url, importMap, cacheKey);
  inFlight.set(cacheKey, loadPromise);

  const module = await loadPromise;
  moduleCache.set(cacheKey, module);
  inFlight.delete(cacheKey);

  return module;
}

async function performLoad(url, importMap, cacheKey) {
  if (importMap) {
    const script = document.createElement('script');
    script.type = 'importmap';
    script.textContent = JSON.stringify(importMap);
    document.head.appendChild(script);
  }

  return import(url);
}

function preload(url, importMap) {
  return loadModule(url, importMap);
}
```

## Minimal A/B Circular Import Example

```javascript
// a.js
export const a = 'module A';
import('./b.js').then(b => console.log(b.b));

export const a2 = 'also A';

// b.js
export const b = 'module B';
import('./a.js').then(a => console.log(a.a));

export const b2 = 'also B';
```

The circular dependency resolves because JavaScript exports are hoisted—both modules complete loading, and the exported values become available once both module records are initialized.

## Why This Is Asked
This question evaluates understanding of closures, Promise deduplication, request cancellation, and caching strategies in building a production-ready fetch helper. It also touches on memory management with LRU caches and handling abortable requests.

## Key Concepts
- Closures for per-key state isolation
- Promise deduplication to prevent redundant network requests
- Cancellation with AbortController for stale requests
- LRU cache implementation using Map for ordered storage
- Edge cases: rapid toggling between keys and stale data handling

## Code Example
```javascript
const api = (() => {
  const inFlight = new Map();
  const cache = new Map();
  const MAX_CACHE = 50;

  function memoFetch(key, options = {}) {
    if (cache.has(key)) {
      const entry = cache.get(key);
      cache.delete(key);
      cache.set(key, entry);
      return Promise.resolve(entry);
    }

    if (inFlight.has(key)) {
      return inFlight.get(key);
    }

    const controller = new AbortController();
    const promise = fetch(key, { ...options, signal: controller.signal })
      .then(res => res.json())
      .then(data => {
        inFlight.delete(key);
        if (cache.size >= MAX_CACHE) {
          const firstKey = cache.keys().next().value;
          cache.delete(firstKey);
        }
        cache.set(key, data);
        return data;
      })
      .catch(err => {
        inFlight.delete(key);
        throw err;
      });

    inFlight.set(key, { promise, controller });
    return promise;
  }

  function cancel(key) {
    if (inFlight.has(key)) {
      inFlight.get(key).controller.abort();
      inFlight.delete(key);
    }
  }

  return { memoFetch, cancel };
})();
```

## Concept Overview
A closure is a fundamental JavaScript concept where an inner function maintains access to variables in its outer (lexical) scope, even when the outer function has completed execution. This creates a private scope for data encapsulation.

## Implementation Details
- Closures are created automatically when functions are defined inside other functions
- The inner function retains a reference to the outer function's variables
- This enables private variables and methods, similar to object-oriented encapsulation
- Memory is managed automatically - closures persist as long as references exist

## Code Example
```javascript
function createCounter() {
  let count = 0; // Private variable

  return {
    increment: function() {
      count++; // Accesses outer scope variable
      return count;
    },
    decrement: function() {
      count--;
      return count;
    },
    getCount: function() {
      return count;
    }
  };
}

const counter = createCounter();
console.log(counter.increment()); // 1
console.log(counter.increment()); // 2
console.log(counter.getCount());  // 2
```

## Common Pitfalls
- **Memory leaks**: Closures can prevent garbage collection if references persist unnecessarily
- **Loop confusion**: Variables in closures capture by reference, not value (use `let` or IIFE)
- **Performance impact**: Creating many closures can affect memory usage
- **`this` binding**: Arrow functions don't have their own `this`, which affects closure behavior

## Why This Is Asked

This question tests mastery of closures, promises, and per-key caching with real-world constraints like deduplicating in-flight requests, enforcing concurrency limits, and implementing TTL-based invalidation.

## Key Concepts

- **Closures and per-key cache state**: Using closures to maintain cache and in-flight maps private to each loader instance
- **In-flight deduplication**: Sharing promises for concurrent requests to the same key to prevent redundant fetches
- **Concurrency control**: Implementing a semaphore pattern with a 3-request cap
- **TTL-based caching**: Storing expiration timestamps and evicting stale entries
- **Background refresh**: Silently refetching expired keys without blocking callers
- **Invalidation semantics**: Manual cache invalidation for real-time scenarios

## Code Example

```javascript
function createResourceLoader(fetcher) {
  const cache = new Map();
  const inFlight = new Map();
  let active = 0;
  const maxConcurrent = 3;
  const waiting = [];

  const acquire = () => new Promise(resolve => {
    if (active < maxConcurrent) {
      active++;
      resolve();
    } else {
      waiting.push(resolve);
    }
  });

  const release = () => {
    if (waiting.length > 0) {
      waiting.shift()();
    } else {
      active--;
    }
  };

  return {
    load(key, ttl = 5000) {
      const cached = cache.get(key);
      const now = Date.now();

      if (cached) {
        if (cached.expiry > now) {
          return cached.value;
        }
        if (!inFlight.has(key)) {
          fetcher(key).then(value => {
            cache.set(key, { value, expiry: Date.now() + ttl });
          });
        }
      }

      if (inFlight.has(key)) {
        return inFlight.get(key);
      }

      const promise = acquire().then(async () => {
        try {
          const value = await fetcher(key);
          cache.set(key, { value, expiry: Date.now() + ttl });
          return value;
        } finally {
          release();
          inFlight.delete(key);
        }
      });

      inFlight.set(key, promise);
      return promise;
    },

    invalidate(key) {
      cache.delete(key);
    }
  };
}

// Mock fetcher
const fetchUser = createResourceLoader(async (id) => {
  console.log(`Fetching user ${id}...`);
  await new Promise(r => setTimeout(r, 100));
  return { id, name: `User ${id}` };
});

// Usage
await fetchUser.load('user:1', 2000);
await fetchUser.load('user:1'); // Uses cache
fetchUser.invalidate('user:1');
await fetchUser.load('user:1'); // Refetches
```

