function createModuleLoader() {
  const cache = new Map();
  const inflight = new Map();
  const queue = [];
  const MAX_CONCURRENT = 4;
  const TTL = 5 * 60 * 1000; // 5 minutes
  const REFRESH_THRESHOLD = 0.8; // refresh when 80% of TTL elapsed

  async function processQueue() {
    while (queue.length > 0 && inflight.size < MAX_CONCURRENT) {
      const { url, resolve, reject } = queue.shift();
      loadModule(url).then(resolve).catch(reject);
    }
  }

  async function loadModule(url) {
    const cached = cache.get(url);
    if (cached && Date.now() - cached.timestamp < cached.ttl) {
      if (Date.now() - cached.timestamp > cached.ttl * REFRESH_THRESHOLD) {
        queueModule(url).then(() => {
          cache.set(url, { 
            module: cache.get(url).module, 
            timestamp: Date.now(), 
            ttl: cached.ttl 
          });
        });
      }
      return cached.module;
    }
    return queueModule(url);
  }

  async function queueModule(url) {
    if (inflight.has(url)) {
      return inflight.get(url);
    }

    if (inflight.size >= MAX_CONCURRENT) {
      return new Promise((resolve, reject) => {
        queue.push({ url, resolve, reject });
      });
    }

    const promise = import(url).then(module => {
      cache.set(url, { module, timestamp: Date.now(), ttl: TTL });
      return module;
    }).finally(() => {
      inflight.delete(url);
      processQueue();
    });

    inflight.set(url, promise);
    return promise;
  }

  return {
    load(url) {
      return loadModule(url);
    },
    invalidate(url) {
      cache.delete(url);
    }
  };
}

// Usage
const loader = createModuleLoader();
const [moduleA, moduleB] = await Promise.all([
  loader.load('./module-a.js'),
  loader.load('./module-b.js')
]);

// After TTL expires, next load triggers background refresh
setTimeout(async () => {
  await loader.load('./module-a.js'); // Refreshed in background
}, 6 * 60 * 1000);
```

