## Code Example

```javascript
function createLoader(baseUrl) {
  const cache = new Map();
  const inFlight = new Map();

  const join = (p) => {
    if (baseUrl.endsWith('/') || p.startsWith('/')) return `${baseUrl}${p}`;
    return `${baseUrl}/${p}`;
  };

  return {
    load(path) {
      const url = join(path);
      return fetch(url).then(r => {
        if (!r.ok) throw new Error(`HTTP ${r.status}`);
        return r.json();
      });
    },

    cachedLoad(path) {
      const key = path;
      const ttl = 10000; // 10 seconds
      const now = Date.now();
      const cached = cache.get(key);
      if (cached && now - cached.t < ttl) return Promise.resolve(cached.v);

      if (inFlight.has(key)) return inFlight.get(key);

      const url = join(path);
      const p = fetch(url).then(r => {
        if (!r.ok) throw new Error(`HTTP ${r.status}`);
        return r.json();
      }).then(v => {
        cache.set(key, { t: Date.now(), v });
        inFlight.delete(key);
        return v;
      }).catch(e => {
        inFlight.delete(key);
        throw e;
      });

      inFlight.set(key, p);
      return p;
    }
  };
}
```

