Create `fromEvent` as a function that returns an `AsyncGenerator`. It attaches one listener per consumer and pushes events to a per-consumer queue. The generator awaits via a deferred Promise. On generator cleanup (`return()`), it removes that specific listener and resolves any pending Promise to gracefully terminate iteration.

```javascript
function fromEvent(target, type) {
  return (async function* () {
    let resolve, promise = new Promise(r => (resolve = r));
    const handler = e => resolve({ value: e, done: false });
    target.addEventListener(type, handler);
    try {
      while (true) {
        yield await (promise);
        promise = new Promise(r => (resolve = r));
      }
    } finally {
      target.removeEventListener(type, handler);
    }
  })();
}

// Usage
const btn = document.querySelector('#myButton');
const stream = fromEvent(btn, 'click');

for await (const event of stream) {
  console.log('Clicked!');
  if (someCondition) {
    await stream.return();
    break;
  }
}
```

Use a closure encapsulating two Maps: `cache` stores entries with timestamps, and `inflight` holds active Promises to deduplicate concurrent requests. The `load(url, {ttl=30000, signal})` method returns cached data if fresh, reuses an in-flight request if one exists, or initiates a new fetch otherwise. Use `refresh(url)` to bypass the cache and force a fresh fetch. Call `stats()` to inspect cache hit/miss counts.

```javascript
function AsyncCacheLoader() {
  const cache = new Map();
  const inflight = new Map();
  const stats = { hits: 0, misses: 0 };

  function isFresh(entry, ttl) {
    return Date.now() - entry.timestamp < ttl;
  }

  return {
    async load(url, { ttl = 30000, signal } = {}) {
      const cached = cache.get(url);
      if (cached && isFresh(cached, ttl)) {
        stats.hits++;
        return cached.data;
      }

      if (inflight.has(url)) {
        stats.hits++;
        return inflight.get(url);
      }

      stats.misses++;
      const promise = fetch(url, { signal })
        .then(response => response.json())
        .then(data => {
          cache.set(url, { data, timestamp: Date.now() });
          inflight.delete(url);
          return data;
        })
        .catch(err => {
          inflight.delete(url);
          throw err;
        });

      inflight.set(url, promise);
      return promise;
    },

    refresh(url) {
      cache.delete(url);
      return this.load(url, { ttl: 0 });
    },

    stats() {
      return { ...stats, size: cache.size };
    }
  };
}

// Usage
const loader = AsyncCacheLoader();
const data1 = loader.load('/api/dashboard', { ttl: 60000 });
const data2 = loader.load('/api/dashboard'); // deduplicated
data1 === data2; // true (same Promise reference)
```

Use a function factory to encapsulate a cache. When fetchUserProfile(userId) is called, check if a valid (non-expired) entry exists in the cache and return it via Promise.resolve(). If a fetch for that userId is already in progress, return the existing Promise to avoid duplicate requests. Otherwise, fetch from /api/users/${userId}, store the response with an expiry timestamp, and return the Promise.

## Why This Is Asked
