// Minimal concurrency-limited debounced fetch per field using closures
function createFieldController(fetchUrl, maxConcurrent = 4) {
  let debounceTimer;
  let abortController;

  return {
    onInput: async (term) => {
      // Cancel previous request
      if (abortController) {
        abortController.abort();
      }

      // Clear existing debounce
      clearTimeout(debounceTimer);

      // Set new debounce
      debounceTimer = setTimeout(async () => {
        // Check global concurrency limit
        if (globalInFlight >= maxConcurrent) {
          await waitForSlot();
        }

        globalInFlight++;
        abortController = new AbortController();

        try {
          const response = await fetch(`${fetchUrl}?q=${term}`, {
            signal: abortController.signal
          });

          if (!abortController.signal.aborted) {
            const suggestions = await response.json();
            updateFieldUI(suggestions);
          }
        } catch (error) {
          if (error.name !== 'AbortError') {
            console.error('Fetch error:', error);
          }
        } finally {
          globalInFlight--;
        }
      }, 300);
    }
  };
}
```

## What are Closures?

Closures are a fundamental JavaScript concept where inner functions maintain access to variables from their outer (lexical) scope, even after the outer function completes execution.

## React Use Case

```javascript
function Counter({ initialCount }) {
  const [count, setCount] = useState(initialCount);

  // This callback creates a closure over 'count'
  const handleClick = useCallback(() => {
    setCount(count + 1); // Accesses outer 'count' variable
  }, [count]);

  return <button onClick={handleClick}>Count: {count}</button>;
}
```

## Key Benefits

- Preserves access to outer scope variables
- Enables powerful patterns in React development
- Maintains state consistency across component re-renders
- Supports memoization and performance optimization

