function createQueue(limit) {
  const q = [];
  let active = 0;
  const next = () => {
    if (active >= limit || q.length === 0) return;
    const { task, resolve, reject } = q.shift();
    active++;
    Promise.resolve()
      .then(() => task())
      .then(resolve)
      .catch(reject)
      .finally(() => {
        active--;
        next();
      });
  };
  return {
    enqueue: (task) => new Promise((resolve, reject) => {
      q.push({ task, resolve, reject });
      next();
    })
  };
}
