// Loader sketch for analytics batching and caching
function createAnalyticsLoader(fetchFn, ttl = 60000) {
  const cache = new Map();
  const inFlight = new Map();

  const keyFor = (ids) => Array.from(new Set(ids)).sort().join(',');

  async function load(ids, { signal } = {}) {
    const key = keyFor(ids);
    const now = Date.now();
    const cached = cache.get(key);
    if (cached && cached.expiresAt > now) return cached.value;

    if (inFlight.has(key)) return inFlight.get(key);

    const p = (async () => {
      let attempt = 0;
      const controller = new AbortController();
      const merged = signal
        ? (signal.addEventListener ? signal : { addEventListener: () => {} }).bind(null)
        : null;
      while (attempt <= 3) {
        try {
          const resp = await fetchFn(`/api/analytics?ids=${encodeURIComponent(key)}`, {
            signal: signal ?? controller.signal,
          });
          if (!resp.ok) throw new Error('Fetch error');
          const data = await resp.json();
          cache.set(key, { value: data, expiresAt: now + ttl });
          inFlight.delete(key);
          return data;
        } catch (e) {
          if (signal?.aborted) throw new DOMException('aborted', 'AbortError');
          attempt++;
          if (attempt > 3) {
            inFlight.delete(key);
            throw e;
          }
          await new Promise((r) => setTimeout(r, Math.pow(2, attempt) * 100));
        }
      }
    })();

    inFlight.set(key, p);
    return p;
  }

  return { load };
}
```

