// store.js
import React from 'react'

export const AppConfigContext = React.createContext({ apiEndpoint: '/api', debounce: 300 })

const initialState = { query: '', results: [] }

function reducer(state, action) {
  switch (action.type) {
    case 'SET_QUERY':
      return { ...state, query: action.payload }
    case 'SET_RESULTS':
      return { ...state, results: action.payload }
    default:
      return state
  }
}

export function useStore() {
  const [state, dispatch] = React.useReducer(reducer, initialState)
  const actions = React.useMemo(() => ({
    setQuery: (q) => dispatch({ type: 'SET_QUERY', payload: q }),
    setResults: (r) => dispatch({ type: 'SET_RESULTS', payload: r })
  }), [])
  return { state, actions }
}
```

