    const id = setTimeout(() => onChange(local), delay)
    return () => clearTimeout(id)
  }, [local, delay, onChange])
  React.useEffect(() => setLocal(value), [value])
  return <input value={local} onChange={(e) => setLocal(e.target.value)} />
}
