// ChatContext.js
const ChatContext = createContext();

const chatReducer = (state, action) => {
  switch (action.type) {
    case 'ADD_MESSAGE':
      return state.map(conv =>
        conv.id === action.payload.conversationId
          ? { ...conv, messages: [...conv.messages, action.payload.text], unread: conv.unread + 1 }
          : conv
      );
    case 'MARK_READ':
      return state.map(conv =>
        conv.id === action.payload.conversationId
          ? { ...conv, unread: 0 }
          : conv
      );
    default:
      return state;
  }
};

export const ChatProvider = ({ children }) => {
  const [conversations, dispatch] = useReducer(chatReducer, initialState);
  return (
    <ChatContext.Provider value={{ conversations, dispatch }}>
      {children}
    </ChatContext.Provider>
  );
};

// DebouncedSearchInput.jsx
const DebouncedSearchInput = ({ onFilter }) => {
  const [query, setQuery] = useState('');

  useEffect(() => {
    const timer = setTimeout(() => onFilter(query), 250);
    return () => clearTimeout(timer);
  }, [query, onFilter]);

  return <input value={query} onChange={e => setQuery(e.target.value)} />;
};

// useMemo selector
export const useUnreadCounts = (conversations) => {
  return useMemo(() => {
    const perConversation = conversations.reduce((acc, conv) => {
      acc[conv.id] = conv.unread;
      return acc;
    }, {});
    const total = conversations.reduce((sum, conv) => sum + conv.unread, 0);
    return { perConversation, total };
  }, [conversations]);
};

