## Code Example
```javascript
// Stream wrapper (per-tenant)
function createTenantStreamStore() {
  const listeners = new Map();
  let state = {};
  return {
    subscribe(tenantId, cb) {
      if (!listeners.has(tenantId)) listeners.set(tenantId, new Set());
      listeners.get(tenantId).add(cb);
      return () => listeners.get(tenantId).delete(cb);
    },
    emit(record) {
      const { tenantId } = record;
      state[tenantId] = state[tenantId] || [];
      state[tenantId].push(record);
      // keep small window for demo purposes
      (listeners.get(tenantId) || new Set()).forEach((cb) => cb(state[tenantId]));
    },
    getSnapshot(tenantId) {
      return (state[tenantId] || []).slice();
    }
  };
}

// Selector (per-tenant top-N with 5-min window)
const topNSelector = (state, tenantId, topN) => {
  const now = Date.now();
  const items = (state[tenantId] || []);
  const windowItems = items.filter(i => now - i.ts <= 5 * 60 * 1000);
  return windowItems
    .slice()
    .sort((a, b) => b.score - a.score)
    .slice(0, topN);
};

// LeaderboardRow (memoized)
const LeaderboardRow = React.memo(function Row({ item, rank }) {
  return (
    <div className="row" role="listitem" aria-label={`#${rank} ${item.userId}`}>#{rank} {item.userId} — {item.score}</div>
  );
});

// Panel integration (pseudocode)
function PerTenantLeaderboardPanel({ topN = 10 }) {
  const { tenantId } = useContext(TenantContext);
  const streamStore = useMemo(createTenantStreamStore, []);
  const snapshot = useSyncExternalStore(
    (cb) => streamStore.subscribe(tenantId, cb),
