// FeatureFlagContext.tsx
import React, { createContext, useContext, useReducer, useEffect, useRef, useCallback } from 'react';

type Action =
  | { type: 'SET_FLAG'; name: string; value: boolean }
  | { type: 'PATCH_FLAGS'; patches: Record<string, boolean> };

type State = Record<string, boolean>;

const reducer = (state: State, action: Action): State => {
  switch (action.type) {
    case 'SET_FLAG':
      return { ...state, [action.name]: action.value };
    case 'PATCH_FLAGS':
      return { ...state, ...action.patches };
    default:
      return state;
  }
};

const FeatureFlagContext = createContext<{
  flags: State;
  dispatch: React.Dispatch<Action>;
} | null>(null);

// Debounce hook
const useDebounce = (callback: () => void, delay: number) => {
  const timeoutRef = useRef<NodeJS.Timeout>();
  const callbackRef = useRef(callback);

  useEffect(() => { callbackRef.current = callback; });

  useEffect(() => {
    return () => clearTimeout(timeoutRef.current);
  }, []);

  return useCallback(() => {
    clearTimeout(timeoutRef.current);
    timeoutRef.current = setTimeout(() => callbackRef.current(), delay);
  }, [delay]);
};

export const FeatureFlagProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [flags, dispatch] = useReducer(reducer, {});
  const debouncedUpdate = useDebounce(() => {
    // Push flag changes to server
    fetch('/api/flags', { method: 'PATCH', body: JSON.stringify(flags) });
  }, 200);

  useEffect(() => { debouncedUpdate(); }, [flags]);

  return (
    <FeatureFlagContext.Provider value={{ flags, dispatch }}>
      {children}
    </FeatureFlagContext.Provider>
  );
};

