  switch (action.type) {
    case 'ADD_FIELD':
      return { ...state, fields: [...state.fields, action.payload] };
    case 'UPDATE_FIELD':
      return {
        ...state,
        fields: state.fields.map(f =>
          f.id === action.payload.id ? { ...f, ...action.payload } : f
        )
      };
    case 'TOGGLE_REQUIRED':
      return {
        ...state,
        fields: state.fields.map(f =>
          f.id === action.payload ? { ...f, required: !f.required } : f
        )
      };
    case 'MOVE_FIELD':
