// Per-tenant feed wrapper with subscription management
function createTenantFeedManager(wsFactory) {
  const connections = new Map(); // tenantId -> WebSocket
  const subscribers = new Map(); // tenantId -> Set of callbacks

  function connect(tenantId) {
    if (connections.has(tenantId)) return;
    const ws = wsFactory(tenantId);
    ws.onmessage = (e) => {
      const data = JSON.parse(e.data);
      subscribers.get(tenantId)?.forEach(cb => cb(data));
    };
    connections.set(tenantId, ws);
    subscribers.set(tenantId, new Set());
  }

  function subscribe(tenantId, callback) {
    connect(tenantId);
    subscribers.get(tenantId).add(callback);
    return () => subscribers.get(tenantId)?.delete(callback);
  }

  function disconnect(tenantId) {
    connections.get(tenantId)?.close();
    connections.delete(tenantId);
    subscribers.delete(tenantId);
  }

  return { subscribe, disconnect };
}

// Memoized selector for rolling bucketed series
const makeRpsSelector = (tenantId, metric = 'rps', windowMs = 60000) => {
  const cache = new Map();
  return (dataPoints) => {
    const now = Date.now();
    const bucketSize = 1000; // 1 second buckets
    const buckets = {};

    for (let i = 0; i < windowMs / bucketSize; i++) {
      buckets[now - i * bucketSize] = 0;
    }

    dataPoints
      .filter(d => d.ts > now - windowMs)
      .forEach(d => {
        const bucket = Math.floor(d.ts / bucketSize) * bucketSize;
        buckets[bucket] = (buckets[bucket] || 0) + d.value;
      });

    return Object.entries(buckets)
      .map(([ts, value]) => ({ ts: Number(ts), value }))
      .sort((a, b) => a.ts - b.ts);
  };
};

// Canvas-based chart with rAF
function ChartCanvas({ data, width = 600, height = 300 }) {
  const canvasRef = useRef(null);
  const rafRef = useRef(null);
  const dataRef = useRef(data);

  useEffect(() => { dataRef.current = data; }, [data]);

  useEffect(() => {
    const canvas = canvasRef.current;
    const ctx = canvas.getContext('2d');
    const dpr = window.devicePixelRatio || 1;

    canvas.width = width * dpr;
    canvas.height = height * dpr;
    ctx.scale(dpr, dpr);

    const draw = () => {
      ctx.clearRect(0, 0, width, height);
      const points = dataRef.current;
      if (!points.length) return;

      const maxVal = Math.max(...points.map(p => p.value), 1);
      const xScale = width / (points.length - 1 || 1);
      const yScale = height / maxVal;

      ctx.beginPath();
      ctx.strokeStyle = '#3b82f6';
      ctx.lineWidth = 2;
      points.forEach((p, i) => {
        const x = i * xScale;
        const y = height - p.value * yScale;
        i === 0 ? ctx.moveTo(x, y) : ctx.lineTo(x, y);
      });
      ctx.stroke();

      rafRef.current = requestAnimationFrame(draw);
    };

    draw();
    return () => cancelAnimationFrame(rafRef.current);
  }, [width, height]);

  return <canvas ref={canvasRef} style={{ width, height }} />;
}

