// Memoized selector keyed by (tenantId, timeWindow)
const selectBoundedEvents = memoize((tenantId, timeWindow) => {
  return (events) => {
    const cutoff = Date.now() - timeWindow;
    return events
      .filter(e => e.tenantId === tenantId && e.timestamp > cutoff)
      .slice(-120); // Bounded to 120 events
  };
});

// React.memo EventRow
const EventRow = memo(({ event }) => (
  <div>{event.action} - {event.timestamp}</div>
));

// Panel wiring
function AuditPanel({ tenantId }) {
  const events = useAuditStream(tenantId);
  const boundedEvents = useMemo(
    () => selectBoundedEvents(tenantId, 120000),
    [tenantId]
  )(events);

  return (
    <div>
      {boundedEvents.map(e => <EventRow key={e.id} event={e} />)}
    </div>
  );
}
```

