const bucketSelector = (state) => state.metrics.stream;

export const selectLast1sBuckets = createSelector(
  bucketSelector,
  (stream) => {
    const now = Date.now();
    const oneSec = 1000;
    const buckets = {};
    for (const p of stream) {
      const bucket = Math.floor((now - p.t) / oneSec);
      buckets[bucket] = (buckets[bucket] || 0) + p.v;
    }
    // return as ordered array of {k,v}
    return Object.keys(buckets).sort((a,b)=>a-b).map(k=>({t: Number(k), v: buckets[k]}));
  }
);
