// Fetch wrapper with deduplication and caching
const fetchCache = new Map();
const pendingRequests = new Map();

const smartFetch = async (url, options = {}) => {
  const cacheKey = `${url}:${JSON.stringify(options)}`;
  const cached = fetchCache.get(cacheKey);

  if (cached && Date.now() - cached.timestamp < 60000) {
    return cached.data;
  }

  if (pendingRequests.has(cacheKey)) {
    return pendingRequests.get(cacheKey);
  }

  const promise = fetch(url, options).then(response => response.json());
  pendingRequests.set(cacheKey, promise);

  try {
    const data = await promise;
    fetchCache.set(cacheKey, { data, timestamp: Date.now() });
    return data;
  } finally {
    pendingRequests.delete(cacheKey);
  }
};

// WebSocket with exponential backoff
const connectWebSocket = (url, maxRetries = 5) => {
  let retryCount = 0;

  const connect = () => {
    const ws = new WebSocket(url);

    ws.onopen = () => {
      retryCount = 0;
      console.log('WebSocket connected');
    };

    ws.onclose = () => {
      if (retryCount < maxRetries) {
        const delay = Math.min(1000 * Math.pow(2, retryCount), 30000);
        setTimeout(connect, delay);
        retryCount++;
      }
    };

    return ws;
  };

  return connect();
};

