## Live Feed Widget Implementation

### API Contracts

**REST API (Initial Load)**
```
GET /api/rides?limit=30&offset=0
Response: {
  "items": [{ "id": "uuid", "rider": "...", "driver": "...", "status": "...", "sequence": 30, "timestamp": "ISO8601" }],
  "nextOffset": 30,
  "hasMore": true
}
```

**WebSocket (Live Updates)**
```
ws://api.rideshare.com/ws?lastSequence=30
Message: { "type": "ride_update", "payload": { "id": "uuid", "sequence": 31, ... } }
```

### Implementation

```javascript
// ride-feed.js
class RideFeed {
  constructor() {
    this.items = new Map();
    this.ws = null;
    this.reconnectAttempts = 0;
    this.maxReconnectDelay = 30000;
    this.batchQueue = [];
    this.dbName = 'ridefeed';
    this.maxCachedItems = 100;
    this.isOnline = navigator.onLine;

    this.init();
  }

  async init() {
    await this.openDB();
    await this.loadCached();
    await this.fetchInitial();
    this.connectWebSocket();
    this.setupOfflineDetection();

    window.addEventListener('online', () => this.handleOnline());
    window.addEventListener('offline', () => this.handleOffline());
  }

  async openDB() {
    return new Promise((resolve, reject) => {
      const request = indexedDB.open(this.dbName, 1);
      request.onupgradeneeded = (e) => {
        const db = e.target.result;
        if (!db.objectStoreNames.contains('items')) {
          db.createObjectStore('items', { keyPath: 'sequence' });
        }
      };
      request.onsuccess = () => { this.db = request.result; resolve(); };
      request.onerror = () => reject(request.error);
    });
  }

  async loadCached() {
    const tx = this.db.transaction('items', 'readonly');
    const store = tx.objectStore('items');
    const items = await new Promise(resolve => {
      const request = store.getAll();
      request.onsuccess = () => resolve(request.result);
    });
    items.sort((a, b) => a.sequence - b.sequence);
    items.forEach(item => this.items.set(item.sequence, item));
    this.render();
  }

  async fetchInitial() {
    if (!this.isOnline) return;

    try {
      const lastSeq = Math.max(...this.items.keys(), 0);
      const res = await fetch(`/api/rides?limit=30&since=${lastSeq}`);
      const data = await res.json();

      data.items.forEach(item => this.items.set(item.sequence, item));
      await this.cacheItems();
      this.render();
    } catch (err) {
      console.error('Fetch failed:', err);
    }
  }

  connectWebSocket() {
    if (!this.isOnline) return;

    const lastSeq = Math.max(...this.items.keys(), 0);
    this.ws = new WebSocket(`wss://api.rideshare.com/ws?lastSequence=${lastSeq}`);

    this.ws.onmessage = (event) => {
      const msg = JSON.parse(event.data);
      if (msg.type === 'ride_update') {
        this.queueUpdate(msg.payload);
      }
    };

    this.ws.onclose = () => this.reconnect();
    this.ws.onerror = () => this.ws.close();
  }

  reconnect() {
    const delay = Math.min(1000 * Math.pow(2, this.reconnectAttempts), this.maxReconnectDelay);
    this.reconnectAttempts++;

    setTimeout(() => {
      console.log(`Reconnecting... attempt ${this.reconnectAttempts}`);
      this.connectWebSocket();
    }, delay);
  }

  queueUpdate(item) {
    this.batchQueue.push(item);
    this.items.set(item.sequence, item);

    if (!this.renderPending) {
      this.renderPending = true;
      requestAnimationFrame(() => this.flushBatch());
    }
  }

  flushBatch() {
    const sorted = this.batchQueue.sort((a, b) => a.sequence - b.sequence);
    this.batchQueue = [];

    this.updateDOM(sorted);
    this.cacheItems();
    this.renderPending = false;
  }

  updateDOM(newItems) {
    const feed = document.getElementById('ride-feed');
    const fragment = document.createDocumentFragment();

    newItems.forEach(item => {
      const el = this.createItemElement(item);
      const existing = feed.querySelector(`[data-sequence="${item.sequence}"]`);
      if (existing) {
        existing.replaceWith(el);
      } else {
        fragment.appendChild(el);
      }
    });

    if (fragment.childNodes.length) {
      feed.appendChild(fragment);
    }
  }

  createItemElement(item) {
    const div = document.createElement('div');
    div.className = 'ride-item';
    div.dataset.sequence = item.sequence;
    div.innerHTML = `
      <span class="rider">${item.rider}</span>
      <span class="driver">${item.driver}</span>
      <span class="status">${item.status}</span>
      <span class="sequence">#${item.sequence}</span>
    `;
    return div;
  }

  async cacheItems() {
    const sortedItems = Array.from(this.items.values())
      .sort((a, b) => b.sequence - a.sequence)
      .slice(0, this.maxCachedItems);

    const tx = this.db.transaction('items', 'readwrite');
    const store = tx.objectStore('items');

    store.clear();
    sortedItems.forEach(item => store.put(item));
  }

  handleOffline() {
    this.isOnline = false;
    this.showOfflineIndicator();
    if (this.ws) {
      this.ws.close();
      this.ws = null;
    }
  }

  async handleOnline() {
    this.isOnline = true;
    this.hideOfflineIndicator();
    this.reconnectAttempts = 0;
    await this.fetchInitial();
    this.connectWebSocket();
  }

  showOfflineIndicator() {
    const indicator = document.getElementById('offline-indicator');
    if (indicator) indicator.style.display = 'block';
  }

  hideOfflineIndicator() {
    const indicator = document.getElementById('offline-indicator');
    if (indicator) indicator.style.display = 'none';
  }

  setupOfflineDetection() {
    if (!this.isOnline) this.showOfflineIndicator();
  }
}
```

### Service Worker (sw.js)
```javascript
const CACHE_NAME = 'ridefeed-v1';
const STATIC_ASSETS = [
  '/ride-feed.js',
  '/styles.css',
  '/index.html'
];

self.addEventListener('install', (event) => {
  event.waitUntil(
    caches.open(CACHE_NAME).then(cache => cache.addAll(STATIC_ASSETS))
  );
  self.skipWaiting();
});

self.addEventListener('fetch', (event) => {
  const { request } = event;

  if (request.url.includes('/api/rides')) {
    event.respondWith(
      fetch(request)
        .catch(() => caches.match(request))
    );
  } else if (request.url.endsWith('.js') || request.url.endsWith('.css')) {
    event.respondWith(
      caches.match(request).then(cached => cached || fetch(request))
    );
  }
});
```

## Trade-offs

| Aspect | Choice | Trade-off |
|--------|--------|-----------|
| IndexedDB vs localStorage | IndexedDB | Better capacity/performance, async API complexity |
| requestAnimationFrame vs setTimeout | rAF | Smooth batching, may delay on hidden tabs |
| Sequence-based ordering | Client-side sort | Ensures order, memory overhead for large feeds |
| Exponential backoff | 2^n with 30s cap | Balances reconnection vs server load |
| Cache size | 100 items | Memory vs offline coverage |
| REST + WebSocket | Hybrid | Simplicity vs eventual consistency challenges |

