// WebSocket wrapper (connect, backoff, send, onMessage)
class WS {
  constructor(url) {
    this.url = url;
    this.ws = null;
    this.reconnectDelay = 1000;
    this.maxReconnectDelay = 30000;
    this.handlers = {};
  }

  connect() {
    this.ws = new WebSocket(this.url);
    this.ws.onopen = () => { this.reconnectDelay = 1000; };
    this.ws.onclose = () => this.reconnect();
    this.ws.onmessage = (e) => {
      const msg = JSON.parse(e.data);
      this.handlers[msg.type]?.(msg.payload);
    };
  }

  reconnect() {
    setTimeout(() => {
      this.reconnectDelay = Math.min(this.reconnectDelay * 2, this.maxReconnectDelay);
      this.connect();
    }, this.reconnectDelay);
  }

  send(type, payload) {
    if (this.ws?.readyState === WebSocket.OPEN) {
      this.ws.send(JSON.stringify({ type, payload }));
    }
  }

  on(type, handler) {
    this.handlers[type] = handler;
  }
}

// opLog for CRDT-like merge
class OpLog {
  constructor() {
    this.ops = [];
    this.vectorClock = {};
  }

  addOp(op) {
    this.ops.push(op);
    this.vectorClock[op.clientId] = (this.vectorClock[op.clientId] || 0) + 1;
  }

  merge(remoteOps) {
    for (const op of remoteOps) {
      const dominated = this.ops.some(local =>
        local.clientId === op.clientId && local.timestamp <= op.timestamp
      );
      if (!dominated) {
        this.ops.push(op);
      }
    }
  }
}

// Service Worker (install/activate/cache)
// sw.js
self.addEventListener('install', (e) => {
  e.waitUntil(
    caches.open('whiteboard-v1').then(cache => cache.addAll(['/', '/index.html', '/app.js']))
  );
  self.skipWaiting();
});

self.addEventListener('activate', (e) => {
  e.waitUntil(
    caches.keys().then(keys =>
      Promise.all(keys.filter(k => k !== 'whiteboard-v1').map(k => caches.delete(k)))
    )
  );
  self.clients.claim();
});

self.addEventListener('fetch', (e) => {
  e.respondWith(
    caches.match(e.request).then(cached => cached || fetch(e.request))
  );
});

// Main render wiring
const canvas = document.getElementById('board');
const ctx = canvas.getContext('2d');
const ws = new WS('ws://localhost:8080');
const opLog = new OpLog();

function render() {
  ctx.clearRect(0, 0, canvas.width, canvas.height);
  for (const op of opLog.ops) {
    ctx.beginPath();
    ctx.moveTo(op.x1, op.y1);
    ctx.lineTo(op.x2, op.y2);
    ctx.stroke();
  }
  requestAnimationFrame(render);
}

canvas.addEventListener('mousemove', (e) => {
  if (e.buttons !== 1) return;
  const op = { x1: lastX, y1: lastY, x2: e.offsetX, y2: e.offsetY };
  opLog.addOp(op);
  ws.send('stroke', op);
  lastX = e.offsetX;
  lastY = e.offsetY;
});

ws.on('stroke', (op) => opLog.addOp(op));
ws.connect();
render();
