// REST/WS wrapper with reconnection
class GridClient {
  constructor(url) { this.url = url; this.ws = null; this.seq = {}; }
  async init() {
    const layout = await fetch(this.url + '/grid').then(r => r.json());
    this.render(layout);
    this.connect();
  }
  connect() {
    this.ws = new WebSocket(this.url.replace('http','ws') + '/stream');
    this.ws.onmessage = e => this.process(JSON.parse(e.data));
    this.ws.onclose = () => setTimeout(() => this.connect(), this.backoff());
  }
  backoff() { return Math.min(30000, (this.attempts || 1) * 1000 * (0.5 + Math.random())); }

  // Patch processor with buffering
  process(patch) {
    const { cellId, seq } = patch;
    if (!this.seq[cellId] || seq > this.seq[cellId]) this.pending[cellId]?.push(patch);
    while (this.pending[cellId]?.length) {
      const p = this.pending[cellId].sort((a,b) => a.seq - b.seq).shift();
      if (p.seq === this.seq[cellId] + 1) { this.apply(p); this.seq[cellId] = p.seq; }
    }
  }
  apply({cellId, op, value}) {
    const el = document.getElementById(cellId);
    if (op === 'set') el.textContent = value;
    else if (op === 'add') el.insertAdjacentHTML('beforeend', value);
    else if (op === 'del') el.remove();
  }
}
```

