```javascript
// 1) Fetch cache wrapper (stale-while-revalidate)
async function fetchSessions(tenantId, cacheName = 'sessions-v1') {
  const url = `/api/sessions?tenantId=${tenantId}&limit=100`;
  const cache = await caches.open(cacheName);
  const cached = await cache.match(url);

  const fetchAndCache = async () => {
    const res = await fetch(url);
    if (res.ok) cache.put(url, res.clone());
    return res.json();
  };

  if (cached) {
    fetchAndCache();
    return cached.json();
  }
  return fetchAndCache();
}

// 2) WebSocket wrapper with exponential backoff + polling fallback
class SessionSocket {
  constructor(tenantId, onMessage, onStatusChange) {
    this.tenantId = tenantId;
    this.onMessage = onMessage;
    this.onStatusChange = onStatusChange;
    this.attempts = 0;
    this.pollInterval = null;
    this.connect();
  }

  getReconnectDelay() {
    return Math.min(1000 * Math.pow(2, this.attempts++), 30000);
  }

  connect() {
    this.ws = new WebSocket(`wss://api/sessions?tenantId=${this.tenantId}`);
    this.ws.onopen = () => { this.attempts = 0; this.onStatusChange('connected'); };
    this.ws.onmessage = e => this.onMessage(JSON.parse(e.data));
    this.ws.onclose = () => { this.onStatusChange('disconnected'); this.reconnect(); };
    this.ws.onerror = () => this.ws.close();
  }

  reconnect() {
    clearInterval(this.pollInterval);
    this.pollInterval = setInterval(() => this.poll(), 5000);
    setTimeout(() => this.connect(), this.getReconnectDelay());
  }

  async poll() {
    try {
      const res = await fetch(`/api/sessions?tenantId=${this.tenantId}&since=${Date.now()}`);
      const data = await res.json();
      data.forEach(patch => this.onMessage(patch));
    } catch {}
  }
}

// 3) Patch applier with last-writer-wins and IndexedDB offline queue
class SessionPane {
  constructor(tenantId) {
    this.sessions = new Map();
    this.db = null;
    this.socket = new SessionSocket(tenantId, this.applyPatch.bind(this));
    this.initDB();
  }

  async initDB() {
    this.db = await openDB('offline-queue', 1, {
      upgrade(db) { db.createObjectStore('edits', { keyPath: 'id', autoIncrement: true }); }
    });
  }

  applyPatch(patch) {
    const existing = this.sessions.get(patch.id);
    if (!existing || patch.ts > existing.ts) {
      this.sessions.set(patch.id, patch);
      this.render();
    }
  }

  render() {
    const container = document.getElementById('sessions');
    const patches = diff(this.prevState, [...this.sessions.values()]);
    patches.forEach(p => applyDOMPatch(container, p));
    this.prevState = [...this.sessions.values()];
  }

  async queueEdit(edit) {
    await this.db.put('edits', { ...edit, queuedAt: Date.now() });
  }

  async replayQueue() {
    const tx = this.db.transaction('edits', 'readwrite');
    const edits = await tx.store.getAll();
    for (const edit of edits.sort((a, b) => a.queuedAt - b.queuedAt)) {
      await fetch('/api/sessions/edit', { method: 'POST', body: JSON.stringify(edit) });
      await tx.store.delete(edit.id);
    }
  }
}
```

