function createWebSocket(url, onMessage) {
  let ws;
  let delay = 1000;
  let stopped = false;
  const connect = () => {
    if (stopped) return;
    ws = new WebSocket(url);
    ws.addEventListener('message', (e) => onMessage(JSON.parse(e.data)));
    ws.addEventListener('close', () => {
      if (stopped) return;
      setTimeout(connect, delay);
      delay = Math.min(delay * 2, 30000);
    });
