// Fetch wrapper sketch
function createFetchWrapper(baseUrl) {
  return async function fetchWrapper(endpoint, options = {}) {
    const cache = await caches.open('inventory-v1');
    const cached = await cache.match(baseUrl + endpoint);

    if (cached && !options.forceRefresh) {
      return cached;
    }

    const response = await fetch(baseUrl + endpoint, options);
    if (response.ok) {
      cache.put(baseUrl + endpoint, response.clone());
    }
    return response;
  };
}

// WebSocket wrapper sketch
function createWsWrapper(url, handlers) {
  let ws = null;
  let retryDelay = 1000;
  const editQueue = [];

  function connect() {
    ws = new WebSocket(url);

    ws.onopen = () => {
      retryDelay = 1000;
      replayQueue();
      handlers.onOpen?.();
    };

    ws.onmessage = (e) => handlers.onMessage(JSON.parse(e.data));

    ws.onclose = () => {
      setTimeout(connect, retryDelay);
      retryDelay = Math.min(retryDelay * 2, 30000);
    };
  }

  function replayQueue() {
    while (editQueue.length) {
      ws.send(JSON.stringify(editQueue.shift()));
    }
  }

  connect();

  return {
    send: (data) => {
      if (ws.readyState === WebSocket.OPEN) {
        ws.send(JSON.stringify(data));
      } else {
        editQueue.push(data);
      }
    }
  };
}

// Diff applier sketch
function applyDiff(currentItems, updates) {
  const itemMap = new Map(currentItems.map(item => [item.id, item]));

  for (const update of updates) {
    const existing = itemMap.get(update.id);
    if (!existing || update.ts > existing.ts) {
      itemMap.set(update.id, update);
    }
  }

  return Array.from(itemMap.values()).sort((a, b) => b.ts - a.ts);
}
```

