class OrderTracker {
  constructor() {
    this.baseDelay = 1000;
    this.maxDelay = 30000;
    this.reconnectAttempt = 0;
  }

  getReconnectDelay() {
    const exponentialDelay = Math.min(
      this.baseDelay * Math.pow(2, this.reconnectAttempt),
      this.maxDelay
    );
    const jitter = Math.random() * 0.3 * exponentialDelay;
    return exponentialDelay + jitter;
  }

  connect() {
    this.ws = new WebSocket('wss://api.instacart.com/orders/live');

    this.ws.onclose = () => {
      this.reconnectAttempt++;
      setTimeout(() => this.connect(), this.getReconnectDelay());
    };

    this.ws.onmessage = (event) => {
      const update = JSON.parse(event.data);
      this.handleOrderUpdate(update);
    };
  }

  async handleOrderUpdate(update) {
    await db.wsMessageQueue.add({ type: update.type, payload: update, receivedAt: Date.now() });
    await db.orders.update(update.orderId, { ...update, updatedAt: Date.now() });
  }
}
