## Conflict Resolution Strategy

```javascript
// Server sends vector clock with each update
// Client maintains local version vector

class ConflictResolver {
  resolve(localOrder, remoteUpdate, localVector, remoteVector) {
    if (this.isConcurrent(localVector, remoteVector)) {
      return this.mergeOrderState(localOrder, remoteUpdate);
    }
    return this.isNewer(remoteVector, localVector) ? remoteUpdate : localOrder;
  }

  mergeOrderState(local, remote) {
    return {
      ...remote,
      items: this.mergeItems(local.items, remote.items),
      status: this.prioritizeStatus(local.status, remote.status),
      estimatedDelivery: remote.estimatedDelivery || local.estimatedDelivery
    };
  }

  prioritizeStatus(local, remote) {
    const order = ['pending', 'confirmed', 'picking', '包装', 'delivering', 'delivered'];
    return order.indexOf(remote) > order.indexOf(local) ? remote : local;
  }
}
```

