    mutationFn: (update) => updateOrderStatus(orderId, update),
    onMutate: async (newStatus) => {
      await queryClient.cancelQueries(['order', orderId]);
      const previous = queryClient.getQueryData(['order', orderId]);
      queryClient.setQueryData(['order', orderId], (old) => ({
        ...old, status: newStatus, _optimistic: true
      }));
      return { previous };
    },
    onError: (err, vars, context) => {
      queryClient.setQueryData(['order', orderId], context.previous);
    },
    onSettled: () => {
      queryClient.invalidateQueries(['order', orderId]);
    }
  });
}
